"use client"

import * as React from "react"
import { cn } from "@/lib/utils"

export function dataWorkspaceTypeBadgeClassName(type?: string): string {
  const normalizedType = (type ?? "text").toLowerCase()

  if (normalizedType === "enum" || normalizedType === "select") {
    return "border-amber-300/60 bg-amber-500/10 text-amber-700 dark:text-amber-300"
  }

  if (normalizedType === "uuid" || normalizedType === "foreign-key" || normalizedType === "link") {
    return "border-sky-300/60 bg-sky-500/10 text-sky-700 dark:text-sky-300"
  }

  if (normalizedType === "datetime" || normalizedType === "date") {
    return "border-violet-300/60 bg-violet-500/10 text-violet-700 dark:text-violet-300"
  }

  if (normalizedType === "boolean") {
    return "border-emerald-300/60 bg-emerald-500/10 text-emerald-700 dark:text-emerald-300"
  }

  if (normalizedType === "json") {
    return "border-rose-300/60 bg-rose-500/10 text-rose-700 dark:text-rose-300"
  }

  return "border-border/70 bg-muted/45 text-muted-foreground"
}

export function dataWorkspaceMetaBadgeClassName(tone: "default" | "primary" | "success" | "danger" = "default"): string {
  if (tone === "primary") {
    return "border-border/70 bg-foreground/[0.06] text-foreground"
  }

  if (tone === "success") {
    return "border-emerald-300/60 bg-emerald-500/10 text-emerald-700 dark:text-emerald-300"
  }

  if (tone === "danger") {
    return "border-destructive/25 bg-destructive/10 text-destructive"
  }

  return "border-border/70 bg-background/70 text-muted-foreground"
}

export function dataWorkspaceRelationBadgeClassName(source?: string): string {
  if (source === "base") {
    return "border-border/70 bg-background/80 text-foreground"
  }

  return "border-border/70 bg-muted/50 text-muted-foreground"
}

export function dataWorkspaceRowClassName(options?: {
  interactive?: boolean
  selected?: boolean
}): string {
  return cn(
    "group border-b transition-colors",
    options?.interactive && "cursor-pointer hover:bg-muted/50",
    options?.selected && "bg-muted hover:bg-muted/70",
  )
}

export interface DataWorkspaceHeaderProps {
  eyebrow?: React.ReactNode
  title: React.ReactNode
  description?: React.ReactNode
  meta?: React.ReactNode
  actions?: React.ReactNode
  className?: string
}

export function DataWorkspaceHeader({
  eyebrow,
  title,
  description,
  meta,
  actions,
  className,
}: DataWorkspaceHeaderProps) {
  return (
    <div className={cn("flex flex-col gap-1.5 sm:flex-row sm:items-center sm:justify-between", className)}>
      <div className="min-w-0 space-y-1">
        <div className="space-y-1">
          {eyebrow ? (
            <p className="text-xs font-medium text-muted-foreground">
              {eyebrow}
            </p>
          ) : null}
          <h3 className="text-lg font-semibold leading-none tracking-tight">
            {title}
          </h3>
          {description ? (
            <p className="text-sm text-muted-foreground">
              {description}
            </p>
          ) : null}
        </div>
        {meta ? (
          <div className="flex flex-wrap items-center gap-1.5 text-xs text-muted-foreground pt-1">
            {meta}
          </div>
        ) : null}
      </div>
      {actions ? (
        <div className="flex shrink-0 flex-wrap items-center gap-2">
          {actions}
        </div>
      ) : null}
    </div>
  )
}

type DataStateTone = "neutral" | "danger" | "success"

export interface DataWorkspaceStateProps extends React.HTMLAttributes<HTMLDivElement> {
  tone?: DataStateTone
  heading?: React.ReactNode
  description: React.ReactNode
}

export function DataWorkspaceState({
  tone = "neutral",
  heading,
  description,
  className,
  ...props
}: DataWorkspaceStateProps) {
  return (
    <div
      className={cn(
        "rounded-lg border p-4 text-sm",
        tone === "danger" && "border-destructive/50 bg-destructive/10 text-destructive",
        tone === "success" && "border-emerald-500/30 bg-emerald-500/10 text-emerald-700 dark:text-emerald-300",
        tone === "neutral" && "border-dashed text-muted-foreground",
        className,
      )}
      {...props}
    >
      <div className="grid gap-1">
        {heading ? (
          <p className="font-medium text-foreground">{heading}</p>
        ) : null}
        <div className={tone === "neutral" ? "text-muted-foreground" : undefined}>
          {description}
        </div>
      </div>
    </div>
  )
}

"use client"

import * as React from "react"
import type { LemmaClient, Table } from "lemma-sdk"
import { useTables } from "lemma-sdk/react"
import { Badge } from "@/components/ui/badge"
import { Button } from "@/components/ui/button"
import {
  Card,
  CardContent,
  CardHeader,
} from "@/components/ui/card"
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select"
import { cn } from "@/lib/utils"
import {
  DataWorkspaceHeader,
  DataWorkspaceState,
  dataWorkspaceMetaBadgeClassName,
} from "@/components/lemma/registry-data-workspace"

export interface LemmaTablePickerProps extends React.HTMLAttributes<HTMLDivElement> {
  client: LemmaClient
  podId?: string
  value?: string
  onValueChange?: (value: string) => void
  title?: string
  description?: string
  placeholder?: string
  limit?: number
  tables?: Table[]
  isLoading?: boolean
  error?: Error | null
  onRefresh?: () => void
}

export const LemmaTablePicker = React.forwardRef<HTMLDivElement, LemmaTablePickerProps>(
  ({
    client,
    podId,
    value,
    onValueChange,
    title = "Table Picker",
    description = "Choose a datastore table.",
    placeholder = "Select a table",
    limit = 100,
    tables,
    isLoading,
    error,
    onRefresh,
    className,
    ...props
  }, ref) => {
  const tablesState = useTables({
    client,
    podId,
    enabled: !tables,
    limit,
  })

  const effectiveTables = tables ?? tablesState.tables
  const effectiveIsLoading = isLoading ?? tablesState.isLoading
  const effectiveError = error ?? tablesState.error
  const selectedTable = effectiveTables.find((table) => table.name === value) ?? null

  return (
    <Card ref={ref} className={cn("", className)} {...props}>
      <CardHeader>
        <DataWorkspaceHeader
          actions={(
            <Button
              disabled={effectiveIsLoading}
              onClick={() => {
                if (onRefresh) {
                  onRefresh()
                  return
                }
                void tablesState.refresh()
              }}
              type="button"
              variant="ghost"
            >
              {effectiveIsLoading ? "Refreshing…" : "Refresh"}
            </Button>
          )}
          description={description}
          eyebrow="Table Context"
          meta={(
            <>
              <Badge className={cn("rounded-full border px-2 py-0.5 text-xs", dataWorkspaceMetaBadgeClassName("default"))} variant="outline">
                {effectiveIsLoading ? "Loading…" : `${effectiveTables.length} table${effectiveTables.length === 1 ? "" : "s"}`}
              </Badge>
              {selectedTable ? (
                <Badge className={cn("rounded-full border px-2 py-0.5 text-xs", dataWorkspaceMetaBadgeClassName("primary"))} variant="outline">
                  {selectedTable.name}
                </Badge>
              ) : null}
            </>
          )}
          title={title}
        />
      </CardHeader>
      <CardContent className="flex flex-col gap-4">
        {effectiveError ? (
          <DataWorkspaceState description={effectiveError.message} tone="danger" />
        ) : null}

        <Select disabled={effectiveTables.length === 0 && effectiveIsLoading} value={value ?? ""} onValueChange={onValueChange}>
          <SelectTrigger id="lemma-table-picker">
            <SelectValue placeholder={placeholder} />
          </SelectTrigger>
          <SelectContent>
            {effectiveTables.map((table) => (
              <SelectItem key={table.name} value={table.name}>
                {table.name}
              </SelectItem>
            ))}
          </SelectContent>
        </Select>

        {!effectiveError ? (
          <DataWorkspaceState
            description={selectedTable
              ? `Using ${selectedTable.name} as the active table for records, forms, and relation views.`
              : effectiveIsLoading
                ? "Loading tables so you can choose the active workspace context."
                : "Choose a table to anchor the records workspace and its related views."}
            heading={selectedTable ? "Active table ready" : "Choose a table"}
          />
        ) : null}
      </CardContent>
    </Card>
  )
})
LemmaTablePicker.displayName = "LemmaTablePicker"
